namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string CourseCode { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Abbreviation { get; set; } = string.Empty;
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z0-9]{6,10}$", ErrorMessage = "Student ID must be 6-10 alphanumeric characters.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Abbreviation = "CS" },
        new() { Id = 2, Name = "Mathematics", Abbreviation = "MATH" },
        new() { Id = 3, Name = "Physics", Abbreviation = "PHYS" },
        new() { Id = 4, Name = "English", Abbreviation = "ENG" },
        new() { Id = 5, Name = "History", Abbreviation = "HIST" },
    ];

    private readonly List<Course> _courses;

    public CatalogService()
    {
        _courses =
        [
            new()
            {
                Id = 1, CourseCode = "CS 101", Title = "Introduction to Programming",
                Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, functions, and object-oriented design principles.",
                Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Alice Chen",
                InstructorBio = "Dr. Chen has 15 years of experience in software engineering and has published extensively on programming pedagogy.",
                DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true
            },
            new()
            {
                Id = 2, CourseCode = "CS 301", Title = "Data Structures and Algorithms",
                Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques including divide-and-conquer, dynamic programming, and greedy algorithms.",
                Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", InstructorName = "Dr. Bob Martinez",
                InstructorBio = "Dr. Martinez specializes in algorithm optimization and competitive programming. He previously worked at a major tech company.",
                DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true
            },
            new()
            {
                Id = 3, CourseCode = "CS 450", Title = "Machine Learning",
                Description = "Introduction to machine learning concepts including supervised learning, unsupervised learning, neural networks, and model evaluation techniques.",
                Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Alice Chen",
                InstructorBio = "Dr. Chen has 15 years of experience in software engineering and has published extensively on programming pedagogy.",
                DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false
            },
            new()
            {
                Id = 4, CourseCode = "MATH 201", Title = "Linear Algebra",
                Description = "Study of vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications to systems of equations.",
                Credits = 3, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Carol Thompson",
                InstructorBio = "Dr. Thompson is an award-winning educator whose research focuses on abstract algebra and its applications.",
                DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true
            },
            new()
            {
                Id = 5, CourseCode = "MATH 301", Title = "Differential Equations",
                Description = "Methods for solving ordinary differential equations, Laplace transforms, series solutions, and systems of differential equations.",
                Credits = 4, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Carol Thompson",
                InstructorBio = "Dr. Thompson is an award-winning educator whose research focuses on abstract algebra and its applications.",
                DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false
            },
            new()
            {
                Id = 6, CourseCode = "PHYS 101", Title = "General Physics I",
                Description = "Introduction to mechanics, thermodynamics, and waves. Includes laboratory component with hands-on experiments.",
                Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Lab Thu 2:00–4:50 PM", InstructorName = "Dr. David Park",
                InstructorBio = "Dr. Park is an experimental physicist with research interests in condensed matter physics and science education.",
                DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true
            },
            new()
            {
                Id = 7, CourseCode = "PHYS 202", Title = "Electromagnetism",
                Description = "Electric fields, magnetic fields, Maxwell's equations, electromagnetic waves, and optics.",
                Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. David Park",
                InstructorBio = "Dr. Park is an experimental physicist with research interests in condensed matter physics and science education.",
                DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false
            },
            new()
            {
                Id = 8, CourseCode = "ENG 101", Title = "Composition and Rhetoric",
                Description = "Develop critical reading and writing skills. Practice crafting argumentative, analytical, and research-based essays.",
                Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", InstructorName = "Prof. Emily Nguyen",
                InstructorBio = "Prof. Nguyen is a published author and rhetoric scholar who has taught writing at the university level for over a decade.",
                DepartmentId = 4, DepartmentName = "English", IsFeatured = false
            },
            new()
            {
                Id = 9, CourseCode = "ENG 250", Title = "American Literature",
                Description = "Survey of American literary works from the colonial period to the present, exploring themes of identity, democracy, and social change.",
                Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", InstructorName = "Prof. Emily Nguyen",
                InstructorBio = "Prof. Nguyen is a published author and rhetoric scholar who has taught writing at the university level for over a decade.",
                DepartmentId = 4, DepartmentName = "English", IsFeatured = false
            },
            new()
            {
                Id = 10, CourseCode = "HIST 101", Title = "World History to 1500",
                Description = "Survey of major civilizations, cultural exchanges, and transformative events from prehistory through the late medieval period.",
                Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Frank Williams",
                InstructorBio = "Dr. Williams is a historian specializing in comparative world history and cross-cultural encounters in the pre-modern era.",
                DepartmentId = 5, DepartmentName = "History", IsFeatured = false
            },
        ];
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real application this would persist to a database.
        return GetCourse(request.CourseId) is not null;
    }
}

