@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="container mt-4">
    <div class="text-center mb-5">
        <h1 class="display-4">University Course Catalog</h1>
        <p class="lead text-muted">Explore departments, browse courses, and submit your enrollment request.</p>
    </div>

    <section class="mb-5">
        <h2>Featured Courses</h2>
        <div class="row">
            @foreach (var course in _featuredCourses)
            {
                <div class="col-md-6 col-lg-3 mb-3">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@course.CourseCode</h5>
                            <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                            <p class="card-text small">@course.Credits credits &bull; @course.DepartmentName</p>
                            <a href="/courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    </section>

    <section class="mb-5">
        <h2>Departments</h2>
        <div class="row">
            @foreach (var dept in _departments)
            {
                <div class="col-md-4 col-lg-3 mb-3">
                    <a href="/courses?departmentId=@dept.Id" class="text-decoration-none">
                        <div class="card text-center h-100">
                            <div class="card-body">
                                <h5 class="card-title">@dept.Abbreviation</h5>
                                <p class="card-text">@dept.Name</p>
                            </div>
                        </div>
                    </a>
                </div>
            }
        </div>
    </section>

    <div class="text-center">
        <a href="/courses" class="btn btn-outline-primary me-2">Browse All Courses</a>
        <a href="/enroll" class="btn btn-success">Enroll Now</a>
    </div>
</div>

@code {
    private List<Course> _featuredCourses = [];
    private List<Department> _departments = [];

    protected override void OnInitialized()
    {
        _featuredCourses = CatalogService.GetFeaturedCourses();
        _departments = CatalogService.GetDepartments();
    }
}

@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService
@inject NavigationManager Navigation
@rendermode InteractiveServer

<PageTitle>Course Catalog</PageTitle>

<div class="container mt-4">
    <h1>Course Catalog</h1>

    <div class="row mb-4">
        <div class="col-md-6">
            <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
                   @bind="SearchTerm" @bind:event="oninput" />
        </div>
        <div class="col-md-4">
            <select class="form-select" @bind="SelectedDepartmentId">
                <option value="0">All Departments</option>
                @foreach (var dept in _departments)
                {
                    <option value="@dept.Id">@dept.Name</option>
                }
            </select>
        </div>
    </div>

    @if (_courses.Count == 0)
    {
        <div class="alert alert-info">No courses found matching your criteria.</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead class="table-dark">
                    <tr>
                        <th>Code</th>
                        <th>Title</th>
                        <th>Department</th>
                        <th>Credits</th>
                        <th>Instructor</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var course in _courses)
                    {
                        <tr>
                            <td>@course.CourseCode</td>
                            <td>@course.Title</td>
                            <td>@course.DepartmentName</td>
                            <td>@course.Credits</td>
                            <td>@course.InstructorName</td>
                            <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    private List<Course> _courses = [];
    private List<Department> _departments = [];
    private string _searchTerm = string.Empty;
    private int _selectedDepartmentId;

    private string SearchTerm
    {
        get => _searchTerm;
        set { _searchTerm = value; LoadCourses(); }
    }

    private int SelectedDepartmentId
    {
        get => _selectedDepartmentId;
        set { _selectedDepartmentId = value; LoadCourses(); }
    }

    protected override void OnInitialized()
    {
        _departments = CatalogService.GetDepartments();

        var uri = new Uri(Navigation.Uri);
        var query = System.Web.HttpUtility.ParseQueryString(uri.Query);
        if (int.TryParse(query["departmentId"], out var deptId))
            _selectedDepartmentId = deptId;

        LoadCourses();
    }

    private void LoadCourses()
    {
        int? deptFilter = _selectedDepartmentId > 0 ? _selectedDepartmentId : null;
        _courses = CatalogService.GetCourses(_searchTerm, deptFilter);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>@(_course?.Title ?? "Course Not Found")</PageTitle>

<div class="container mt-4">
    @if (_course is null)
    {
        <div class="alert alert-warning">Course not found.</div>
        <a href="/courses" class="btn btn-secondary">Back to Catalog</a>
    }
    else
    {
        <nav aria-label="breadcrumb">
            <ol class="breadcrumb">
                <li class="breadcrumb-item"><a href="/">Home</a></li>
                <li class="breadcrumb-item"><a href="/courses?departmentId=@_course.DepartmentId">@_course.DepartmentName</a></li>
                <li class="breadcrumb-item active">@_course.CourseCode</li>
            </ol>
        </nav>

        <h1>@_course.CourseCode &mdash; @_course.Title</h1>

        <div class="row mt-4">
            <div class="col-md-8">
                <h4>Description</h4>
                <p>@_course.Description</p>

                <h4 class="mt-4">Schedule</h4>
                <p><span class="badge bg-secondary">@_course.Schedule</span></p>

                <h4 class="mt-4">Credits</h4>
                <p><strong>@_course.Credits</strong> credit hours</p>
            </div>
            <div class="col-md-4">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">Instructor</h5>
                        <h6>@_course.InstructorName</h6>
                        <p class="card-text small">@_course.InstructorBio</p>
                    </div>
                </div>
                <div class="mt-3">
                    <a href="/enroll?courseId=@_course.Id" class="btn btn-success w-100">Enroll in This Course</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? _course;

    protected override void OnInitialized()
    {
        _course = CatalogService.GetCourse(Id);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Enrollment Request</PageTitle>

<div class="container mt-4">
    <h1>Enrollment Request</h1>
    <p class="text-muted">Complete the form below to request enrollment in a course.</p>

    @if (_submitted)
    {
        <div class="alert alert-success">
            <h4 class="alert-heading">Request Submitted!</h4>
            <p>Your enrollment request for <strong>@_selectedCourseTitle</strong> has been received. You will be notified once it is processed.</p>
            <a href="/courses" class="btn btn-primary mt-2">Browse More Courses</a>
        </div>
    }
    else
    {
        <EditForm Model="_request" OnValidSubmit="HandleSubmit" FormName="EnrollmentForm">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger mb-3" />

            <div class="mb-3">
                <label for="studentName" class="form-label">Full Name</label>
                <InputText id="studentName" class="form-control" @bind-Value="_request.StudentName" />
                <ValidationMessage For="() => _request.StudentName" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="studentId" class="form-label">Student ID</label>
                <InputText id="studentId" class="form-control" @bind-Value="_request.StudentId" />
                <ValidationMessage For="() => _request.StudentId" class="text-danger" />
                <div class="form-text">Your alphanumeric student ID (6-10 characters, e.g., STU12345).</div>
            </div>

            <div class="mb-3">
                <label for="courseSelect" class="form-label">Course</label>
                <InputSelect id="courseSelect" class="form-select" @bind-Value="_request.CourseId">
                    <option value="0">-- Select a course --</option>
                    @foreach (var course in _courses)
                    {
                        <option value="@course.Id">@course.CourseCode - @course.Title</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => _request.CourseId" class="text-danger" />
            </div>

            <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
        </EditForm>
    }
</div>

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest _request { get; set; } = new();

    private List<Course> _courses = [];
    private bool _submitted;
    private string _selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        _courses = CatalogService.GetCourses();

