@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService
@inject NavigationManager Navigation
@rendermode InteractiveServer

<PageTitle>Course Catalog</PageTitle>

<div class="container mt-4">
    <h1>Course Catalog</h1>

    <div class="row mb-4">
        <div class="col-md-6">
            <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
                   @bind="SearchTerm" @bind:event="oninput" />
        </div>
        <div class="col-md-4">
            <select class="form-select" @bind="SelectedDepartmentId">
                <option value="0">All Departments</option>
                @foreach (var dept in _departments)
                {
                    <option value="@dept.Id">@dept.Name</option>
                }
            </select>
        </div>
    </div>

    @if (_courses.Count == 0)
    {
        <div class="alert alert-info">No courses found matching your criteria.</div>
    }
    else
    {
        <div class="table-responsive">
            <table class="table table-striped table-hover">
                <thead class="table-dark">
                    <tr>
                        <th>Code</th>
                        <th>Title</th>
                        <th>Department</th>
                        <th>Credits</th>
                        <th>Instructor</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var course in _courses)
                    {
                        <tr>
                            <td>@course.CourseCode</td>
                            <td>@course.Title</td>
                            <td>@course.DepartmentName</td>
                            <td>@course.Credits</td>
                            <td>@course.InstructorName</td>
                            <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    }
</div>

@code {
    private List<Course> _courses = [];
    private List<Department> _departments = [];
    private string _searchTerm = string.Empty;
    private int _selectedDepartmentId;

    private string SearchTerm
    {
        get => _searchTerm;
        set { _searchTerm = value; LoadCourses(); }
    }

    private int SelectedDepartmentId
    {
        get => _selectedDepartmentId;
        set { _selectedDepartmentId = value; LoadCourses(); }
    }

    protected override void OnInitialized()
    {
        _departments = CatalogService.GetDepartments();

        var uri = new Uri(Navigation.Uri);
        var query = System.Web.HttpUtility.ParseQueryString(uri.Query);
        if (int.TryParse(query["departmentId"], out var deptId))
            _selectedDepartmentId = deptId;

        LoadCourses();
    }

    private void LoadCourses()
    {
        int? deptFilter = _selectedDepartmentId > 0 ? _selectedDepartmentId : null;
        _courses = CatalogService.GetCourses(_searchTerm, deptFilter);
    }
}

