@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Enrollment Request</PageTitle>

<div class="container mt-4">
    <h1>Enrollment Request</h1>
    <p class="text-muted">Complete the form below to request enrollment in a course.</p>

    @if (_submitted)
    {
        <div class="alert alert-success">
            <h4 class="alert-heading">Request Submitted!</h4>
            <p>Your enrollment request for <strong>@_selectedCourseTitle</strong> has been received. You will be notified once it is processed.</p>
            <a href="/courses" class="btn btn-primary mt-2">Browse More Courses</a>
        </div>
    }
    else
    {
        <EditForm Model="_request" OnValidSubmit="HandleSubmit" FormName="EnrollmentForm">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger mb-3" />

            <div class="mb-3">
                <label for="studentName" class="form-label">Full Name</label>
                <InputText id="studentName" class="form-control" @bind-Value="_request.StudentName" />
                <ValidationMessage For="() => _request.StudentName" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="studentId" class="form-label">Student ID</label>
                <InputText id="studentId" class="form-control" @bind-Value="_request.StudentId" />
                <ValidationMessage For="() => _request.StudentId" class="text-danger" />
                <div class="form-text">Your alphanumeric student ID (6-10 characters, e.g., STU12345).</div>
            </div>

            <div class="mb-3">
                <label for="courseSelect" class="form-label">Course</label>
                <InputSelect id="courseSelect" class="form-select" @bind-Value="_request.CourseId">
                    <option value="0">-- Select a course --</option>
                    @foreach (var course in _courses)
                    {
                        <option value="@course.Id">@course.CourseCode - @course.Title</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => _request.CourseId" class="text-danger" />
            </div>

            <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
        </EditForm>
    }
</div>

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest _request { get; set; } = new();

    private List<Course> _courses = [];
    private bool _submitted;
    private string _selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        _courses = CatalogService.GetCourses();

        var uri = new Uri(Navigation.Uri);
        var query = System.Web.HttpUtility.ParseQueryString(uri.Query);
        if (int.TryParse(query["courseId"], out var courseId))
            _request.CourseId = courseId;
    }

    private void HandleSubmit()
    {
        var success = CatalogService.SubmitEnrollmentRequest(_request);
        if (success)
        {
            _selectedCourseTitle = _courses.FirstOrDefault(c => c.Id == _request.CourseId)?.Title ?? "Unknown";
            _submitted = true;
        }
    }
}

