                            <p class="card-text small">@course.Credits credits &bull; @course.DepartmentName</p>
                            <a href="/courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    </section>

    <section class="mb-5">
        <h2>Departments</h2>
        <div class="row">
            @foreach (var dept in _departments)
            {
                <div class="col-md-4 col-lg-3 mb-3">
                    <a href="/courses?departmentId=@dept.Id" class="text-decoration-none">
                        <div class="card text-center h-100">
                            <div class="card-body">
                                <h5 class="card-title">@dept.Abbreviation</h5>
                                <p class="card-text">@dept.Name</p>
                            </div>
                        </div>
                    </a>
                </div>
            }
        </div>
    </section>

    <div class="text-center">
        <a href="/courses" class="btn btn-outline-primary me-2">Browse All Courses</a>
        <a href="/enroll" class="btn btn-success">Enroll Now</a>
    </div>
</div>

@code {
    private List<Course> _featuredCourses = [];
    private List<Department> _departments = [];

    protected override void OnInitialized()
    {
        _featuredCourses = CatalogService.GetFeaturedCourses();
        _departments = CatalogService.GetDepartments();
    }
}

